 1→import type { MittwaldCliToolHandler } from '../../../../../types/mittwald/conversation.js';
 2→import { formatToolResponse } from '../../../../../utils/format-tool-response.js';
 3→import { createMysqlDatabase, LibraryError } from '@mittwald-mcp/cli-core';
 4→import { sessionManager } from '../../../../../server/session-manager.js';
 5→import { getCurrentSessionId } from '../../../../../utils/execution-context.js';
 6→import { logger } from '../../../../../utils/logger.js';
 7→
 8→interface MittwaldDatabaseMysqlCreateArgs {
 9→  description: string;
10→  version: string;
11→  projectId?: string;
12→  quiet?: boolean;
13→  collation?: string;
14→  characterSet?: string;
15→  userPassword?: string;
16→  userExternal?: boolean;
17→  userAccessLevel?: "full" | "readonly";
18→  timeout?: string;
19→  enable?: boolean;
20→  disable?: boolean;
21→  email?: string;
22→  url?: string;
23→  command?: string;
24→  interpreter?: string;
25→}
26→
27→export const handleDatabaseMysqlCreateCli: MittwaldCliToolHandler<MittwaldDatabaseMysqlCreateArgs> = async (args, sessionId) => {
28→  const effectiveSessionId = sessionId || getCurrentSessionId();
29→
30→  if (!effectiveSessionId) {
31→    return formatToolResponse('error', 'Session ID required');
32→  }
33→
34→  if (!args.projectId) {
35→    return formatToolResponse(
36→      'error',
37→      "Project ID is required for database creation. Please provide --project-id or set a default project context via 'mw context set --project-id=<PROJECT_ID>'."
38→    );
39→  }
40→
41→  const session = await sessionManager.getSession(effectiveSessionId);
42→  if (!session?.mittwaldAccessToken) {
43→    return formatToolResponse('error', 'No Mittwald access token found in session. Please authenticate first.');
44→  }
45→
46→  try {
47→    // Build character settings if provided
48→    const characterSettings = (args.collation || args.characterSet) ? {
49→      ...(args.collation && { collation: args.collation }),
50→      ...(args.characterSet && { characterSet: args.characterSet }),
51→    } : undefined;
52→
53→    const result = await createMysqlDatabase({
54→      projectId: args.projectId!,
55→      description: args.description,
56→      version: args.version,
57→      characterSettings,
58→      apiToken: session.mittwaldAccessToken,
59→    });
60→
61→    return formatToolResponse(
62→      'success',
63→      `Successfully created MySQL database '${args.description}'`,
64→      result.data,
65→      {
66→        durationMs: result.durationMs,
67→      }
68→    );
69→  } catch (error) {
70→    if (error instanceof LibraryError) {
71→      return formatToolResponse('error', error.message, {
72→        code: error.code,
73→        details: error.details,
74→      });
75→    }
76→
77→    logger.error('[WP06] Unexpected error in database mysql create handler', { error });
78→    return formatToolResponse('error', `Failed to create MySQL database: ${error instanceof Error ? error.message : String(error)}`);
79→  }
80→};
